import React from "react";
import { Routes, Route } from "react-router-dom";
import DashboardLayout from "./components/DashboardLayout";
import Home from "./pages/Home";
import Bikes from "./pages/Bikes";
import Booking from "./pages/Booking";
import BookingsManagement from "./pages/BookingsManagement";
import Analytics from "./pages/Analytics";
import Customers from "./pages/Customers";
import Contact from "./pages/Contact";
import Settings from "./pages/Settings";
import Terms from "./pages/Terms";

function App() {
  return (
    <Routes>
      <Route path="/" element={
        <DashboardLayout title="Dashboard" subtitle="Overview">
          <Home />
        </DashboardLayout>
      } />
      <Route path="/fleet" element={
        <DashboardLayout title="Fleet Management" subtitle="Bikes">
          <Bikes />
        </DashboardLayout>
      } />
      <Route path="/bookings" element={
        <DashboardLayout title="Bookings" subtitle="Management">
          <BookingsManagement />
        </DashboardLayout>
      } />
      <Route path="/booking/:bikeId" element={
        <DashboardLayout title="New Booking" subtitle="Create">
          <Booking />
        </DashboardLayout>
      } />
      <Route path="/analytics" element={
        <DashboardLayout title="Analytics" subtitle="Reports">
          <Analytics />
        </DashboardLayout>
      } />
      <Route path="/customers" element={
        <DashboardLayout title="Customers" subtitle="Management">
          <Customers />
        </DashboardLayout>
      } />
      <Route path="/contact" element={
        <DashboardLayout title="Support Center" subtitle="Help">
          <Contact />
        </DashboardLayout>
      } />
      <Route path="/settings" element={
        <DashboardLayout title="Settings" subtitle="Configuration">
          <Settings />
        </DashboardLayout>
      } />
      <Route path="/terms" element={
        <DashboardLayout title="Legal" subtitle="Terms & Policies">
          <Terms />
        </DashboardLayout>
      } />
    </Routes>
  );
}

export default App;
